<template>
  <div class="container">
    <div class="title">最新评论</div>
    <div class="content">
      <ul>
        <li v-for="item in datas" :key="item.id">
          <div class="info">
            <span>{{ item.username }}</span>
          </div>
          <div class="word">{{ item.comments }}</div>
        </li>
      </ul>
    </div>
  </div>
</template>

<script>
import axios from "axios";
export default {
  created() {
    axios.get("/api/comment/newComments").then(res => {
      this.datas = res.data.newComments;
    });
  },
  data() {
    return {
      datas: []
    };
  }
};
</script>

