<template>
  <div id="search">
    <el-input v-model="keyword" placeholder="请输入内容" @keyup.enter.native="search"></el-input>
    <el-button class="btn" @click="search">搜索</el-button> 
  </div>
</template>


<script>
import axios from 'axios'
export default {
  data() {
    return {
      keyword: ""
    };
  },
  methods: {
    search(){
      this.$router.push({name: 'seekIndex',query:{keyword:this.keyword}})
      this.keyword = ''
    }
  }
};
</script>

