<template>
  <div>
    <div class="container" v-for="item in datas" :key="item.id">
      <div class="content">
        <!-- <router-link tag="h2" :to="{name: 'details',query: {
          id : item.id
        }}">{{ item.title }}</router-link> -->
        <h2 @click="handle(item.id)">{{ item.title }}</h2>
        <div class="protect" v-html="item.content"></div>
      </div>
      <footer>发布于{{ new Date(item.utime * 1000).toLocaleDateString() }} | 浏览({{ item.views }}) | Tags：{{ item.tags}}</footer>
    </div>
  </div>
</template>

<script>
import axios from "axios";
export default {
  props: ["datas"],
  data(){
    return {
      id: ''
    }
  },
  methods: {
    handle(id){
      axios.post('/api/article/addViews',{
        id: id
      })
      this.$router.push({name: 'details',query:{id,id}})
    }
  }
};
</script>

