<template>
  <div class="container">
    <div class="title">随机标签</div>
    <div class="content">
      <span
        class="tags"
        v-for="item in tags"
        :key="item.id"
        :style="{color:randomColor(),fontSize:randomSize()}"
        @click="handle(item.tag)"
      >{{ item.tag }}</span>
    </div>
  </div>
</template>

<script>
import axios from "axios";
export default {
  created() {
    axios.get("/api/tag/getAll").then(res => {
      this.tags = res.data.tags;
    });
  },
  data() {
    return {
      tags: ""
    };
  },
  methods: {
    handle(tag) {
      this.$router.push({ name: "tagIndex", query: { tag: tag } });
    }
  },
  computed: {
    randomColor() {
      return function() {
        var r = Math.floor(Math.random() * 255);
        var g = Math.floor(Math.random() * 255);
        var b = Math.floor(Math.random() * 255);
        return `rgb(${r},${g},${b})`;
      };
    },
    randomSize() {
      return function() {
        return Math.floor(Math.random() * 20) + 12 + "px";
      };
    }
  }
};
</script>

