import Vue from 'vue'
import VueRouter from 'vue-router'
import layout from '../layout/Layout.vue'
import index from '../views/index'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'home',
    component: layout,
    redirect: '/index',
    children: [{
      path: 'index',
      name: 'index',
      component : index
    },{
      path: 'tagIndex',
      name: 'tagIndex',
      component: () => import ('../views/TagIndex')
    },{
      path: 'seekIndex',
      name: 'seekIndex',
      component: () => import ('../views/SeekIndex')
    },{
      path: 'details',
      name: 'details',
      component: () => import ('../views/Details')
    },{
      path: 'about',
      name: 'about',
      component: () => import ('../views/About')
    },{
      path: 'note',
      name: 'note',
      component: () => import ('../views/Note')
    },]
  }]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})

export default router
