<template>
  <div class="aaa">
    <word />
    <blog :datas="datas"/>
    <el-pagination
      background
      layout="prev, pager, next"
      class="a"
      :total="total"
      :page-size="pageSize"
      @current-change="handle"
      :current-page="currentPage"
    ></el-pagination>
  </div>
</template>

<script>
import word from "./Word";
import blog from "./Article";

import axios from 'axios'
export default {
  components: {
    word,
    blog
  },
  created(){
    axios.get("/api/article/search").then(res => {
      this.datas = res.data.datas
      this.total = res.data.total
    });
  },
  data() {
    return {
      datas: [],
      total: 10,
      currentPage: 1,
      pageSize: 7
    };
  },
  methods: {
    handle(newPage) {
      this.currentPage = newPage;
      axios
        .get("/api/article/search", {
          params: {
            page: newPage,
            pageSize: this.pageSize
          }
        })
        .then(res => {
          this.total = res.data.total;
          this.datas = res.data.datas;
        });
    }
  }
};
</script>

<style scoped>
.aaa {
  display: inline-block;
}
</style>