<template>
  <div class="container">
    <div class="title">最近热门</div>
    <div class="content">
      <ul>
        <li v-for="item in datas" :key="item.id" @click="handle(item.id)">{{ item.title }}</li>
      </ul>
    </div>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  created(){
    axios.get('/api/article/orderByViews').then( res => {
      this.datas = res.data.data
    })
  },
  data(){
    return {
      datas: []
    }
  },
  methods: {
    handle(id){
      axios.post('/api/article/addViews',{
        id: id
      })
      this.$router.push({name: 'details',query:{id:id}})
    }
  }
};
</script>

